type ProviderFetchOpts = { name: string; base: string; getAuthHeader: (agentId, boardId) => Promise<string>; defaultHeaders?: Record<string,string>; timeoutMs?: number; nullStatuses?: number[]; jsonContentTypeOnlyWithBody?: boolean };
export function createProviderFetch(opts: ProviderFetchOpts) {
  return async function providerFetch(path: string, agentId, boardId, options: Record<string, any> = {}) {
    const auth = await opts.getAuthHeader(agentId, boardId);
    const url = path.startsWith('http') ? path : `${opts.base}${path}`;
    const res = await fetch(url, { signal: AbortSignal.timeout(options.raw ? 120_000 : (opts.timeoutMs ?? 60_000)), ...options, headers: { Authorization: auth, 'Content-Type': 'application/json', ...opts.defaultHeaders, ...(options.headers || {}) } });
    if (!res.ok) throw new Error(`${opts.name} API error ${res.status}: ${await res.text()}`);
    if (opts.nullStatuses?.includes(res.status)) return null;
    if (options.raw) return res;
    return (res.headers.get('content-type') || '').includes('application/json') ? res.json() : res.text();
  };
}

