private async _callAgentClient(cacheKey, server, headers, toolName, args) {
  let client = this.agentClients.get(cacheKey);
  if (!client?.isConnected) client = await this._connectAgentClient(cacheKey, server, headers);
  try { return this._shape(await client.callTool(toolName, args)); }
